SELECT * FROM task

    status = 1 AND expire_time > NOW()

        AND public_desc LIKE CONCAT('%', #{keyword}, '%')


        AND type = #{type}


        AND reward >= #{minReward}


        AND reward <= #{maxReward}


ORDER BY created_at DESC

SELECT * FROM task

    status = 1 AND expire_time > NOW()

        AND type = #{type}


        AND pickup_address LIKE CONCAT('%', #{pickupAddress}, '%')


        AND delivery_address LIKE CONCAT('%', #{deliveryAddress}, '%')


        AND require_sex = #{requireSex}


        AND reward >= #{minReward}


        AND reward <= #{maxReward}


ORDER BY created_at DESC
